def us_slavery(year):
   year = int(year)
   if 1619 <= year <= 1863:
      self = 'enslaved'
   else:
      self = 'free'
      return self
def heir(I):
   I = 'his sorrowful, terrible heir'
   return I
def lucifer(state):
   I = 'self'
   if state == 'no':
      lucifer = 'Black_Lucifer'
      return lucifer
   else:
      I = heir(I)
      return I
def sleepers():
   I = 'hell-name'
   self = 'Curse'
   year = int(input('What year is it? '))
   self = us_slavery(year)
   if 1849 <= year < 1881:
      state = input('Was Black Lucifer dead? ')
      I = lucifer(state)
      if I != 'Black_Lucifer':
         print('I am',I)
         I = ['the God of Revolt','deathless','sorrowful','vast']
         for i in I:
            print('I am',i)
      else:
         if not self:
            print('REVOLT')
   elif year >=1881:
      print('A show of the summer softness\na contact of something unseen\nan amour of the
               light and air')
   elif 1776 <=year < 1849:
      print('We hold these truths to be self-evident\nthat all men are created
                  equal')
   else:
      print('Replica of the Great Hole of history')
sleepers()

class TreebankUnit(HookTest.units.TESTUnit):
    tests = ["parsable", "has_root"]
    readable = {
        "parsable": "File parsing",
        "has_root": "Root declared"
    }

    def __init__(self, path):
        super(HookTest.units.TESTUnit, self).__init__(path)

    def has_root(self):
        # Process
        self.log("If something needs to be verbose")
        has_root = True  # Assign result as a boolean
        yield has_root

    def test(self, scheme):
        tests = [] + CTSUnit.tests
        tests.append(scheme)

        for testname in tests:
            # Show the logs and return the status
            for status in getattr(self, testname)():
                yield (
                   TreebankUnit.readable[testname],
                   status,
                   self.logs
                )
        self.flush()


